import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.wfnuidXa.js";const _=JSON.parse('{"title":"架构说明","description":"","frontmatter":{},"headers":[],"relativePath":"reference/architecture.md","filePath":"reference/architecture.md","lastUpdated":1780989355000}'),i={name:"reference/architecture.md"};function o(l,t,c,h,n,s){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="架构说明" tabindex="-1">架构说明 <a class="header-anchor" href="#架构说明" aria-label="Permalink to &quot;架构说明&quot;">​</a></h1><p>LiteWaf 由控制面、管理界面、数据面网关和状态服务组成。</p><h2 id="组件边界" tabindex="-1">组件边界 <a class="header-anchor" href="#组件边界" aria-label="Permalink to &quot;组件边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>组件</th><th>技术</th><th>职责</th></tr></thead><tbody><tr><td>API</td><td>Go 标准库</td><td>鉴权、配置管理、发布、日志查询、备份恢复和版本信息</td></tr><tr><td>Dashboard</td><td>Vue 3 + TypeScript + Vite + Naive UI</td><td>后台管理、配置编辑、发布预览和观测页面</td></tr><tr><td>Gateway</td><td>OpenResty + LuaJIT</td><td>代理、名单、限流、规则检测、拦截和异步日志</td></tr><tr><td>PostgreSQL</td><td>PostgreSQL</td><td>配置、用户、角色、审计、日志和统计数据</td></tr><tr><td>Redis</td><td>Redis</td><td>轻量运行状态和计数辅助</td></tr></tbody></table><h2 id="配置流" tabindex="-1">配置流 <a class="header-anchor" href="#配置流" aria-label="Permalink to &quot;配置流&quot;">​</a></h2><ol><li>用户在 Dashboard 保存配置。</li><li>Dashboard 调用 <code>/api/v1</code> 管理接口。</li><li>API 写入数据库并生成发布预览。</li><li>用户确认发布。</li><li>API 生成版本化网关配置。</li><li>Gateway 拉取或刷新本地配置并在请求链路执行。</li><li>Gateway 输出访问日志和 WAF 事件，API 汇总后供后台查询。</li></ol><h2 id="请求链路" tabindex="-1">请求链路 <a class="header-anchor" href="#请求链路" aria-label="Permalink to &quot;请求链路&quot;">​</a></h2><p>Gateway 热路径不访问远程数据库。黑白名单、静态资源、健康检查和部分无关请求优先短路；请求体检测和上传元数据检测按配置启用。</p><p>更完整的边界说明见 <a href="https://github.com/newz-max/litewaf-api/blob/master/doc/%E6%9E%B6%E6%9E%84%E8%AF%B4%E6%98%8E.md" target="_blank" rel="noreferrer"><code>litewaf-api/doc/架构说明.md</code></a>。</p>',9)])])}const b=e(i,[["render",o]]);export{_ as __pageData,b as default};
